    }
    reverse(submatrix.begin(), submatrix.end());
    for (int i = 0; i < k; ++i) {
        for (int j = 0; j < k; ++j) {
            newGrid[x + i][y + j] = submatrix[i][j];
        }
    }
    return newGrid;
}
